class Solution {
public:
    int findKthNumber(int n, int k) {
        long long curr = 1;
        k--;
        while (k > 0) {
            long long step = 0, first = curr, last = curr + 1;
            while (first <= n) {
                step += min((long long)n + 1, last) - first;
                first *= 10;
                last *= 10;
            }
            if (k >= step) {
                k -= step;
                curr++;
            } else {
                k--;
                curr *= 10;
            }
        }
        return (int)curr;
    }
};
